import{_ as i,o as e,c as o,ae as t}from"./chunks/framework.CyZiF_rV.js";const k=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"pl/tryby-offline.md","filePath":"pl/tryby-offline.md"}'),n={name:"pl/tryby-offline.md"};function r(l,a,y,s,d,w){return e(),o("div",null,[...a[0]||(a[0]=[t('<h2 id="tryby-offline" tabindex="-1">Tryby offline <a class="header-anchor" href="#tryby-offline" aria-label="Permalink to &quot;Tryby offline&quot;">​</a></h2><p>10.07.2025</p><h2 id="wstep" tabindex="-1">Wstęp <a class="header-anchor" href="#wstep" aria-label="Permalink to &quot;Wstęp&quot;">​</a></h2><p>W systemie KSeF dostępne są dwa podstawowe tryby wystawiania faktur:</p><ul><li>tryb <code>online</code> - faktura wystawiana i przesyłana w czasie rzeczywistym do systemu KSeF,</li><li>tryb <code>offline</code> - faktura wystawiana i przesyłana do KSeF w późniejszym, ustawowo określonym terminie.</li></ul><p>W trybie offline faktury wystawiane są elektronicznie, zgodnie z obowiązującym wzorem struktury FA(3). Najważniejsze aspekty techniczne:</p><ul><li>Przy wysyłce faktury – zarówno w trybie interaktywnym, jak i wsadowym – należy ustawić parametr <code>offlineMode: true</code>.</li><li>W przypadku faktur przesyłanych jako online (offlineMode: false) system KSeF samodzielnie może przypisać im tryb offline - na podstawie porównania daty wystawienia z datą przyjęcia. Szczegóły mechanizmu: <a href="./offline/automatyczne-okreslanie-trybu-offline.html">Automatyczne określanie trybu wysyłki offline</a>.</li><li>Za datę wystawienia system KSeF przyjmuje wyłącznie wartość zawartą w polu <code>P_1</code> struktury e-faktury.</li><li>Data otrzymania faktury to data nadania numeru KSeF lub w przypadku udostępnienia poza KSeF, data faktycznego jej otrzymania.</li><li>Po wystawieniu faktury w trybie offline aplikacja kliencka powinna wygenerować dwa <a href="./kody-qr.html">kody QR</a> służące do wizualizacji faktury: <ul><li><strong>KOD I</strong> – umożliwia weryfikację faktury w systemie KSeF,</li><li><strong>KOD II</strong> – potwierdza tożsamość wystawcy.</li></ul></li><li>Fakturę korygującą przesyła się dopiero po nadaniu numeru KSeF dokumentowi pierwotnemu.</li><li>W przypadku gdy przesłana faktura offline zostanie odrzucona z przyczyn technicznych, możliwe jest skorzystanie z mechanizmu <a href="/ksef-docs/offline/korekta-techniczna.html">korekty technicznej</a>.</li></ul><h3 id="zestawienie-trybow-wystawiania-faktur-w-ksef-–-offline24-offline-i-awaryjny" tabindex="-1">Zestawienie trybów wystawiania faktur w KSeF – offline24, offline i awaryjny <a class="header-anchor" href="#zestawienie-trybow-wystawiania-faktur-w-ksef-–-offline24-offline-i-awaryjny" aria-label="Permalink to &quot;Zestawienie trybów wystawiania faktur w KSeF – offline24, offline i awaryjny&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tryb</th><th>Strona odpowiedzialności</th><th>Okoliczności uruchomienia</th><th>Termin przesłania do KSeF</th><th>Podstawa prawna</th></tr></thead><tbody><tr><td><strong>offline24</strong></td><td>klient</td><td>Brak ograniczeń (dowolność podatnika)</td><td>do następnego dnia roboczego po dacie wystawienia</td><td>art. 106nda ustawy o VAT (projekt KSeF 2.0)</td></tr><tr><td><strong>offline</strong></td><td>system KSeF</td><td>Niedostępność systemu (ogłoszona w BIP i oprogramowaniu interfejsowym)</td><td>do następnego dnia roboczego po zakończeniu niedostępności</td><td>art. 106nh ustawy o VAT (od 1 II 2026)</td></tr><tr><td><strong>awaryjny</strong></td><td>system KSeF</td><td>Awaria KSeF (komunikat w BIP MF i w oprogramowaniu interfejsowym)</td><td>do 7 dni rob. od zakończenia awarii (przy kolejnym komunikacie licznik liczony od nowa)</td><td>art. 106nf ustawy o VAT (od 1 II 2026)</td></tr></tbody></table><h3 id="termin-przesłania-faktury-do-ksef-przy-kolejnych-zdarzeniach" tabindex="-1">Termin przesłania faktury do KSeF przy kolejnych zdarzeniach <a class="header-anchor" href="#termin-przesłania-faktury-do-ksef-przy-kolejnych-zdarzeniach" aria-label="Permalink to &quot;Termin przesłania faktury do KSeF przy kolejnych zdarzeniach&quot;">​</a></h3><p>W trybach offline24 i offline, jeśli w oczekiwanym okresie dosyłania faktury zostanie ogłoszona awaria KSeF (komunikat w BIP MF lub w oprogramowaniu interfejsowym), termin przesłania przesuwa się i jest liczony od dnia zakończenia ostatnio ogłoszonej awarii, nie dłużej niż 7 dni roboczych.</p><p>W trybie awaryjnym, jeżeli podczas siedmiodniowego okresu na dosłanie faktury pojawi się kolejny komunikat o awarii, licznik terminu resetuje się i biegnie od dnia zakończenia tej kolejnej awarii.</p><p>Ogłoszenie awarii całkowitej w trakcie któregokolwiek z powyższych trybów powoduje zniesienie obowiązku przesyłania faktur do KSeF.</p><h4 id="przykład-tryb-offline24-z-ogłoszona-awaria-ksef" tabindex="-1">Przykład: tryb offline24 z ogłoszoną awarią KSeF <a class="header-anchor" href="#przykład-tryb-offline24-z-ogłoszona-awaria-ksef" aria-label="Permalink to &quot;Przykład: tryb offline24 z ogłoszoną awarią KSeF&quot;">​</a></h4><ol><li>2025-07-08 (środa) <ul><li>Podatnik generuje fakturę w trybie offline24 (offlineMode = true).</li><li>Termin przesłania do KSeF ustala się na 2025-07-09 (następny dzień roboczy).</li></ul></li><li>2025-07-09 (czwartek) <ul><li>Ministerstwo Finansów publikuje komunikat o awarii KSeF (BIP i interfejs API).</li><li>Zgodnie z zasadą: pierwotny termin zostaje przesunięty, a nowy liczony jest od dnia zakończenia awarii.</li></ul></li><li>2025-07-12 (sobota) <ul><li>Awaria zostaje usunięta – system ponownie dostępny.</li><li>Rozpoczyna się okres 7 dni roboczych na dosłanie zaległej faktury.</li></ul></li><li>2025-07-22 (wtorek) <ul><li>Upływa termin 7 dni roboczych od zakończenia awarii.</li><li>Aplikacja do tej daty ma czas na wysyłkę faktury do KSeF z ustawionym offlineMode = true.</li></ul></li></ol><h3 id="tryb-awarii-całkowitej" tabindex="-1">Tryb awarii całkowitej <a class="header-anchor" href="#tryb-awarii-całkowitej" aria-label="Permalink to &quot;Tryb awarii całkowitej&quot;">​</a></h3><p>W przypadku ogłoszenia awarii całkowitej (środki społecznego przekazu: TV, radio, prasa, Internet):</p><ul><li>Fakturę można wystawić w formie papierowej lub elektronicznej, bez obowiązku stosowania wzoru FA(3).</li><li>Nie ma obowiązku przesyłania faktury do KSeF po ustaniu awarii.</li><li>Przekazanie nabywcy odbywa się dowolnym kanałem (osobiście, e-mail, inne).</li><li>Datą wystawienia jest zawsze datą faktyczna wskazana na fakturze a data otrzymania data faktycznego otrzymania faktury zakupu.</li><li>Faktury z tego trybu nie są opatrywane kodami QR.</li><li>Faktura korygująca w trakcie trwającej awarii KSeF wystawiana jest analogicznie – poza KSeF, z datą faktyczną.</li></ul><h2 id="powiazane-dokumenty" tabindex="-1">Powiązane dokumenty <a class="header-anchor" href="#powiazane-dokumenty" aria-label="Permalink to &quot;Powiązane dokumenty&quot;">​</a></h2><ul><li><a href="./offline/korekta-techniczna.html">Korekta techniczna faktury offline</a></li><li><a href="./kody-qr.html">Kody QR</a></li></ul>',20)])])}const u=i(n,[["render",r]]);export{k as __pageData,u as default};
